import{ChaosGame}from"./class.min.js";import{DownloadButton,GenerateButton}from"/scripts/components/buttons.min.js";import{TextBox}from"/scripts/components/textBoxes.min.js";import{$}from"/scripts/src/main.min.js";export default function(){const e=new ChaosGame({canvas:$("#output-canvas")}),n=(new GenerateButton({element:$("#generate-button"),onClick:o}),new DownloadButton({element:$("#download-button"),applet:e,filename:()=>"a-chaos-game.png"}),new TextBox({element:$("#resolution-input"),name:"Resolution",value:1500,minValue:100,maxValue:3e3,onEnter:o})),t=new TextBox({element:$("#num-vertices-input"),name:"Vertices",value:5,minValue:3,maxValue:7,onEnter:o});function o(){e.run({resolution:n.value,numVertices:t.value})}}